examples.turtle:
@prefix icm:  <http://tio.models.tmforum.org/tio/v3.6.0/IntentCommonModel/> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix ex:   <http://example.org/tio-instance/FS-D01/> .

ex:intent a icm:Intent .
ex:exp-del a icm:DeliveryExpectation ;
  icm:target ex:tgt ;
  rdfs:comment "Deliver an enterprise 5G slice service."@en .
ex:tgt a icm:Target ;
  rdfs:comment "Connectivity scope between Kaohsiung and Pingtung."@en .

@prefix icm:  <http://tio.models.tmforum.org/tio/v3.6.0/IntentCommonModel/> .
@prefix rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix ex:   <http://example.org/tio-instance/FS-P01/> .

ex:intent a icm:Intent .
ex:tgt a icm:Target ;
  rdfs:comment "Video conferencing traffic."@en .
ex:exp-latency a icm:PropertyExpectation ;
  icm:target ex:tgt ;
  rdfs:comment "Latency should stay below 20 ms."@en .
ex:target-property-values icm:valuesOfTargetProperty rdf:value .

@prefix icm:  <http://tio.models.tmforum.org/tio/v3.6.0/IntentCommonModel/> .
@prefix rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix ex:   <http://example.org/tio-instance/FS-MP01/> .

ex:intent a icm:Intent .
ex:tgt a icm:Target ;
  rdfs:comment "Enterprise backup connectivity."@en .
ex:exp-throughput a icm:PropertyExpectation ;
  icm:target ex:tgt ;
  rdfs:comment "Downlink throughput should be greater than 200 Mbps."@en .
ex:exp-latency a icm:PropertyExpectation ;
  icm:target ex:tgt ;
  rdfs:comment "Latency should stay below 15 ms."@en .
ex:target-property-values icm:valuesOfTargetProperty rdf:value .

@prefix icm:  <http://tio.models.tmforum.org/tio/v3.6.0/IntentCommonModel/> .
@prefix rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix ex:   <http://example.org/tio-instance/FS-C01/> .

ex:intent a icm:Intent ;
  icm:context ex:ctx .
ex:ctx a icm:Context ;
  rdfs:comment "Weekend evening time window."@en .
ex:tgt a icm:Target ;
  rdfs:comment "Backup traffic in the campus network."@en .
ex:exp-prop a icm:PropertyExpectation ;
  icm:target ex:tgt ;
  rdfs:comment "Backup traffic should stay below 300 Mbps."@en .
ex:target-property-values icm:valuesOfTargetProperty rdf:value .

@prefix icm:  <http://tio.models.tmforum.org/tio/v3.6.0/IntentCommonModel/> .
@prefix log:  <http://tio.models.tmforum.org/tio/v3.6.0/LogicalOperators/> .
@prefix rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix ex:   <http://example.org/tio-instance/FS-L01/> .

ex:intent a icm:Intent .
ex:cond a log:Condition ;
  rdfs:comment "Backhaul latency is greater than 15 ms."@en .
ex:tgt a icm:Target ;
  rdfs:comment "Background synchronization traffic."@en .
ex:exp-prop a icm:PropertyExpectation ;
  icm:target ex:tgt ;
  rdfs:comment "Background synchronization traffic should use lower priority."@en .
ex:target-property-values icm:valuesOfTargetProperty rdf:value .

@prefix icm:  <http://tio.models.tmforum.org/tio/v3.6.0/IntentCommonModel/> .
@prefix rdf:  <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix ex:   <http://example.org/tio-instance/FS-X01/> .

ex:intent a icm:Intent ;
  icm:context ex:ctx .
ex:ctx a icm:Context ;
  rdfs:comment "Remote maintenance is in progress."@en .
ex:tgt-control a icm:Target ;
  rdfs:comment "Control signaling."@en .
ex:tgt-video a icm:Target ;
  rdfs:comment "Monitoring video stream."@en .
ex:exp-prop a icm:PropertyExpectation ;
  icm:target ex:tgt-control ;
  rdfs:comment "Control signal latency should stay below 5 ms."@en .
ex:exp-del a icm:DeliveryExpectation ;
  icm:target ex:tgt-video ;
  rdfs:comment "Monitoring video stream should remain uninterrupted."@en .
ex:target-property-values icm:valuesOfTargetProperty rdf:value .
